SELECT 
    id, 
    order_id as "orderId", 
    carrier, 
    tracking_number as "trackingNumber", 
    status, 
    state_id as "stateId", 
    created_at as "createdAt"
FROM shipments

    AND order_id = #{orderId}
    AND status = #{status}
    AND state_id = #{stateId}

${orderby} ${pagination}

SELECT count(*) FROM shipments

    AND order_id = #{orderId}
    AND status = #{status}
    AND state_id = #{stateId}
